def get_relation(type1, type2):
    if type1 in RELATIONS and type2 in RELATIONS[type1]:
        return RELATIONS[type1][type2]
    return {'name': 'Неизвестные отношения', 'desc': 'Описание для данной пары пока не добавлено.'}
